import{_ as p}from"./chunks/immortalwrt.BUmB0cxm.js";import{_ as e,c as o,o as a,ag as r}from"./chunks/framework.KLbWPeN7.js";const _=JSON.parse('{"title":"360 WIFI 6路由器T7 2026最新开箱拆机刷OpenWrt教程!","description":"","frontmatter":{},"headers":[],"relativePath":"flash-tutorials/360t7.md","filePath":"flash-tutorials/360t7.md"}'),i={name:"flash-tutorials/360t7.md"};function l(s,t,n,u,f,d){return a(),o("div",null,t[0]||(t[0]=[r('<h1 id="_360-wifi-6路由器t7-2026最新开箱拆机刷openwrt教程" tabindex="-1">360 WIFI 6路由器T7 2026最新开箱拆机刷OpenWrt教程! <a class="header-anchor" href="#_360-wifi-6路由器t7-2026最新开箱拆机刷openwrt教程" aria-label="Permalink to &quot;360 WIFI 6路由器T7 2026最新开箱拆机刷OpenWrt教程!&quot;">​</a></h1><p>360T7中国电信运营商的定制机，是目前百元以下路由器中性价比很高的AX3000 Wi-Fi 6路由器，具有价格便宜、信号强、支持刷机可玩性高。360 T7和H3C NX30 Pro、小米 WR30U 的硬件配置完全一样，用的都是百元路由器神U MT7981B，arm A53 双核 1.3Ghz，256M 的内存，也都是内置功放 Wi-Fi 信号很好，360T7理论支持发射32个wifi信号，唯一缺点刷机不方便，需要拆机使用TTL工具刷机，普通家庭使用值得推荐！当然如果你的带机量超过200台以上，可以私聊博主推荐更好的路由器！</p><h2 id="📦-准备工作" tabindex="-1">📦 准备工作 <a class="header-anchor" href="#📦-准备工作" aria-label="Permalink to &quot;📦 准备工作&quot;">​</a></h2><p>1.360T7 路由器一台（我买的是电信定制版），我买的二手价格65元左右！</p><p>2.准备一跟网线，一台windows系统电脑。</p><p>3.下载刷机工具包，固件我都放在了网盘里面，兄弟们自取！</p><blockquote><p>📺 视频教程：<br><a href="https://youtu.be/veF0hI0VrV8" target="_blank" rel="noreferrer">点击观看 YouTube 视频教程</a></p></blockquote><ul><li>360T7 路由器刷机工具包：</li></ul><p>仅需 ¥4.4元 <a href="/shop/360t7.html">👉 立即购买</a>（网盘发货，收集固件录制视频不易感谢支持！）</p><h2 id="一、开启telnet和uboot控制台" tabindex="-1">一、开启telnet和uboot控制台 <a class="header-anchor" href="#一、开启telnet和uboot控制台" aria-label="Permalink to &quot;一、开启telnet和uboot控制台&quot;">​</a></h2><ul><li>因为原厂uboot只支持36M大小的固件，显然不适合我们，所以我直接刷入支持108M大分区的uboot，下面跟着我的教程操作吧！</li></ul><p>1、路由器TTL连接电脑，查看视频，打开SSH工具，选择串口，波特率选择 115200</p><p>2、路由器上电，等待机器启动后，不断按下 f 和 回车键 ，直到出现下面的提示后，即可进入failsafe模式!</p><p>Press the [f] key and hit [enter] to enter failsafe mode</p><p>出现上面提示说明成功，如果不成功重复上电知道成功为止！</p><p>3、在failsafe模式依次执行以下操作</p><p>开启uboot控制台菜单 fw_setenv bootmenu_delay 3</p><p>挂载rootfs并开启telnet mount_root sed -i &#39;s/.<em>local debug=.</em>/\\tlocal debug=1/&#39; /etc/init.d/telnet</p><p>修改root密码（输入两次密码确认，不会显示） passwd root</p><p>4、备份原厂固件（可选）</p><p>网上很多教程这里就不写了！</p><p>5、重启路由器进入原厂uboot刷机</p><p>reboot</p><p>重启后就可以拆掉TTL连接线了</p><h2 id="二、刷入uboot" tabindex="-1">二、刷入uboot <a class="header-anchor" href="#二、刷入uboot" aria-label="Permalink to &quot;二、刷入uboot&quot;">​</a></h2><ul><li><p>用网线把电脑和路由器通信，连接到路由器的lan口上，这个路由器的ip地址：192.168.2.1 用ssh工具telnet连接路由器，输入用户名：root 密码就是刚刚设置的密码</p></li><li><p>打开HFS工具选择IP地址，选择IP地址，这里多网口的同志一定要选对，然后把uboot文件拖到HFS工具中，然后复制下载地址</p></li></ul><p>回到ssh工具，输入下载命令下载Uboot到路由器里面，每个人的都不一样，不要直接复制我的！</p><p>wget <a href="http://192.168.2.202/mt7981_360t7-fip-fixed-parts.bin" target="_blank" rel="noreferrer">http://192.168.2.202/mt7981_360t7-fip-fixed-parts.bin</a></p><p>校验MD5 校验值</p><p>md5sum mt7981_360t7-fip-fixed-parts.bin</p><p>输入以下命令刷入Uboot</p><p>mtd write mt7981_360t7-fip-fixed-parts.bin fip</p><p>校验（Verify）刚刚写入 fip 分区的数据，是否与源文件完全一致，输出 Success 字样，说明引导程序刷入成功，没有出错。</p><p>mtd verify mt7981_360t7-fip-fixed-parts.bin fip</p><p>刷机过程中绝对不要断开路由器的电源或中断操作！一旦中途断电，会导致路由器的底层引导程序损坏，路由器将彻底无法启动（俗称“变砖”）</p><h2 id="三、刷入openwrt固件" tabindex="-1">三、刷入OpenWrt固件 <a class="header-anchor" href="#三、刷入openwrt固件" aria-label="Permalink to &quot;三、刷入OpenWrt固件&quot;">​</a></h2><p>刷入不死uboot后你的路由器就可以输入各种openwrt定制系统了，玩法多样！</p><p>确认刷入完毕后，拔掉路由器电源。因为uboot没有DHCP功能，需要手动将电脑的IP地址设置为固定的192.168.1.1，接着按住路由器的RESET按钮后通电开机，</p><p>等待8s后查看绿灯亮起。然后松开reset，浏览器进入192.168.1.1，进入uboot刷机界面。</p><p>刷机界面选择固件，点击upload 等待刷入完成后点击update， 路由器会自动重启,进入刷好的固件系统！</p><p>237大佬的固件</p><p>ip地址：192.168.6.1</p><p>登录密码：password</p><p>bleachwrt固件</p><p>ip地址：192.168.1.1 用户名：root 密码：password</p><p>kwrt固件</p><p>ip地址：10.0.0.1 用户名：root 密码：root</p><p>openwrt</p><p>IP：192.168.1.1 用户：root 密码：password</p><ul><li><p>注意新版GD芯片的闪存千万不要降级！只要刷入降级固件必成砖！</p></li><li><p>收集整理不容易！记得视频点赞关注就是对我最大的支持！</p></li></ul><p><img src="'+p+'" alt="CasaOS界面"></p>',51)]))}const m=e(i,[["render",l]]);export{_ as __pageData,m as default};
